mapper.select:
select distinct * from (select kb.id as id, ct.sw_id as swId, kb.title as title, ct.name as categoryName, case when kb.auth = user.id then user.real_name end as userName, kb.pub_time as createTime, kb.status AS status, kb.dept_id as deptId, kb.remark as remark, case when t2.num is null then 0 else t2.num end as readCount from kb_basic kb join kb_category ct on ct.id = kb.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id,user.id uid,dept.parents from castle_sys_dept dept join castle_sys_user user on user.dept_id=dept.id) dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join castle_sys_user user on kb.auth = user.id left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id
join kb_model_ks_${extendList[0].code} model_ks on kb.id = model_ks.data_id
where kb.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and ct.sw_id= #{kbBasicDto.swId} and (au.user_id =#{uid} or groupu.user_id=#{uid} or dept.uid=#{uid}) and ((kb.status in(1,2) and kb.auth=#{uid}) or kb.status=1 ) and au.kb_auth in (
#{kb_auth}
)
AND kb.title like concat('%',#{kbBasicDto.title},'%')
AND ct.id = #{kbBasicDto.authId}
AND kb.dept_id = #{kbBasicDto.deptId}
AND user.real_name like concat('%', #{kbBasicDto.userName},'%')
AND kb.status = #{kbBasicDto.status}
AND (kb.pub_time >= #{kbBasicDto.fromTime } and kb.pub_time <= #{kbBasicDto.endTime})
and ct.id in (
#{categoryId}
)
and model_ks.${extend.field} ="${extend.data}"
and model_ks.${extend.field} like concat('%', "${extend.data}",'%')
union select distinct kb.id as id, ct.sw_id as swId, kb.title as title, ct.name as categoryName, user.real_name as userName, kb.pub_time as createTime, kb.status AS status, kb.dept_id as deptId, kb.remark as remark, case when t2.num is null then 0 else t2.num end as readCount from kb_basic kb join kb_category ct on ct.id = kb.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join castle_sys_user user on (user.id = kb.auth and au.user_id = user.id or (user.id = groupu.user_id and user.id = kb.auth) or (user.dept_id = dept.id and user.id = kb.auth)) left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id
join kb_model_ks_${extendList[0].code} model_ks on kb.id = model_ks.data_id
where kb.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and user.id=#{uid} and ct.sw_id=#{kbBasicDto.swId} and ((kb.status in(1,2) and kb.auth=#{uid}) or kb.status=1 ) and au.kb_auth =3
AND kb.title like concat('%',#{kbBasicDto.title},'%')
AND ct.id = #{kbBasicDto.authId}
AND kb.dept_id = #{kbBasicDto.deptId}
AND user.real_name like concat('%', #{kbBasicDto.userName},'%')
AND kb.status = #{kbBasicDto.status}
AND (kb.pub_time >= #{kbBasicDto.fromTime } and kb.pub_time <= #{kbBasicDto.endTime})
and ct.id in (
#{categoryId}
)
and model_ks.${extend.field} ="${extend.data}"
and model_ks.${extend.field} like concat('%', "${extend.data}",'%')
) t
order by t.createTime ASC
order by t.createTime DESC
order by CAST( readCount AS UNSIGNED) DESC
order by CAST( readCount AS UNSIGNED) ASC
limit #{map.offset},#{map.rows}

