join kb_model_ks_${extendList[0].code} model_ks on kb.id = model_ks.data_id
where kb.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and user.id=#{uid} and ct.sw_id=#{kbBasicDto.swId} and ((kb.status in(1,2) and kb.auth=#{uid}) or kb.status=1 ) and au.kb_auth in (
#{kb_auth}
)
AND kb.title like concat('%',#{kbBasicDto.title},'%')
AND ct.id = #{kbBasicDto.authId}
AND kb.dept_id = #{kbBasicDto.deptId}
AND user.real_name like concat('%', #{kbBasicDto.userName},'%')
AND kb.status = #{kbBasicDto.status}
AND (kb.pub_time >= #{kbBasicDto.fromTime } and kb.pub_time <= #{kbBasicDto.endTime})
and ct.id in (
#{categoryId}
)
and model_ks.${extend.field} like concat('%', "${extend.data}",'%')
union select distinct kb.id as id, ct.sw_id as swId, kb.title as title, ct.name as categoryName, user.real_name as userName, kb.pub_time as createTime, ct.status AS status, kb.dept_id as deptId, kb.remark as remark, case when t2.num is null then 0 else t2.num end as readCount from kb_basic kb join kb_category ct on ct.id = kb.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join castle_sys_user user on (user.id = kb.auth and au.user_id = user.id and (user.id = groupu.user_id and user.id = kb.auth) and (user.dept_id = dept.id and user.id = kb.auth)) left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id
join kb_model_ks_${extendList[0].code} model_ks on kb.id = model_ks.data_id
where kb.is_deleted = 2 and au.is_deleted = 2 and kb.status = 1 and ct.is_deleted = 2 and user.id=#{uid} and ct.sw_id=#{kbBasicDto.swId} and ((kb.status in(1,2) and kb.auth=#{uid}) or kb.status=1 ) and au.kb_auth =3
AND kb.title like concat('%',#{kbBasicDto.title},'%')
AND ct.id = #{kbBasicDto.authId}
AND kb.dept_id = #{kbBasicDto.deptId}
AND user.real_name like concat('%', #{kbBasicDto.userName},'%')
AND kb.status = #{kbBasicDto.status}
AND (kb.pub_time >= #{kbBasicDto.fromTime } and kb.pub_time <= #{kbBasicDto.endTime})
and ct.id in (
#{categoryId}
)
and model_ks.${extend.field} like concat('%', "${extend.data}",'%')
) t

select *
from kb_basic
where title = #{kbBasicDto.title}
  and is_deleted = 2
  and auth = #{kbBasicDto.auth}
  and dept_id = #{kbBasicDto.deptId}
  and category_id = #{kbBasicDto.categoryId}

select distinct base.*, user.real_name as userName, ct.name as cateName, base.dept_id as deptId from kb_basic base join kb_category ct on ct.id = base.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id, user.id uid from castle_sys_dept dept join castle_sys_user user on (dept.id = user.dept_id or dept.parents like concat('%',user.dept_id,'%'))) dept on dept.id = au.user_id join castle_sys_user user on base.auth = user.id where base.is_deleted = 2 and au.is_deleted = 2 and ct.is_deleted = 2 and base.id =#{bid} and (au.user_id = #{uid} or groupu.user_id = #{uid} or dept.uid = #{uid}) and au.kb_auth in (
#{kb_auth}
)

select kb.id as id, ct.sw_id as swId, kb.title as title, ct.name as categoryName, user.real_name as userName, kb.pub_time as createTime, kb.remark as remark, kb.status AS status, kb.dept_id as deptId, case when t2.num is null then 0 else t2.num end as readCount from kb_basic kb join kb_category ct on kb.category_id =ct.id join castle_sys_user user on user.id =kb.auth join castle_sys_dept dept on dept.id = kb.dept_id left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id
join kb_model_ks_${extendList[0].code} model_ks on kb.id = model_ks.data_id
where kb.is_deleted=2 and ct.sw_id=#{kbBasicDto.swId}
AND kb.title like concat('%',#{kbBasicDto.title},'%')
AND kb.dept_id = #{kbBasicDto.deptId}
AND user.real_name like concat('%', #{kbBasicDto.userName},'%')
AND kb.status = #{kbBasicDto.status}
AND (kb.pub_time >= #{kbBasicDto.fromTime } and kb.pub_time <= #{kbBasicDto.endTime})
and ct.id in (
#{categoryId}
)
and model_ks.${extend.field} ="${extend.data}"
and model_ks.${extend.field} like concat('%', "${extend.data}",'%')
order by kb.pub_time ASC
order by kb.pub_time DESC
order by CAST( readCount AS UNSIGNED) DESC
order by CAST( readCount AS UNSIGNED) ASC
limit #{map.offset},#{map.rows}

select count(1) from kb_basic kb join kb_category ct on kb.category_id =ct.id join castle_sys_user user on user.id =kb.auth join castle_sys_dept dept on dept.id = kb.dept_id left join (select b_id, count(1) num from kb_basic_user t where t.type = 1 group by b_id) t2 on t2.b_id = kb.id
join kb_model_ks_${extendList[0].code} model_ks on kb.id = model_ks.data_id
where kb.is_deleted=2 and ct.sw_id=#{kbBasicDto.swId}
AND kb.title like concat('%',#{kbBasicDto.title},'%')
AND kb.dept_id = #{kbBasicDto.deptId}
AND user.real_name like concat('%', #{kbBasicDto.userName},'%')
AND kb.status = #{kbBasicDto.status}
AND (kb.create_time > #{kbBasicDto.fromTime } and kb.create_time <= #{kbBasicDto.endTime})
and ct.id in (
#{categoryId}
)
and model_ks.${extend.field} ="${extend.data}"
and model_ks.${extend.field} like concat('%', "${extend.data}",'%')
order by kb.sort desc

select kb.id as id,kb.title as title,csu.nickname as createName,kc.name as ctName,kb.create_time as pubTime FROM kb_basic kb LEFT JOIN castle_sys_user csu ON kb.auth = csu.id LEFT JOIN kb_category kc ON kb.category_id = kc.id where kb.id in (
#{id}
)

select t.id, ct.sw_id as swId, title, user.real_name as userName, t.create_time as createTime, ct.name as categoryName
from kb_basic t join castle_sys_user user on user.id = t.auth join kb_category ct on ct.id = t.category_id
t.is_deleted=2 and t.status = 1
and ct.sw_id = #{swId}
ORDER BY RAND() limit #{map.rows}

select distinct t.id, title, ct.sw_id as swId, user.real_name as userName, t.create_time as createTime, ct.name as categoryName from kb_basic t join kb_category ct on ct.id = t.category_id join kb_warehouse_auth au on ((t.id = au.wh_id and au.category = 01 and au.status = 1) or (t.id = au.wh_id and au.category = 01 and au.status = 2) or (t.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id, user.id uid,dept.parents from castle_sys_dept dept join castle_sys_user user on user.dept_id = dept.id) dept on ( dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join castle_sys_user user on t.auth = user.id WHERE ct.is_deleted = 2 and au.is_deleted=2 and t.is_deleted=2 and t.status = 1
and ct.sw_id = #{swId}
and (au.user_id =#{uid} or groupu.user_id=#{uid} or dept.uid=#{uid}) and au.kb_auth in (
#{kb_auth}
) union select distinct t.id, title, ct.sw_id as swId, user.real_name as userName, t.create_time as createTime, ct.name as categoryName from kb_basic t join kb_category ct on ct.id = t.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join castle_sys_user user on (user.id = t.auth and au.user_id = user.id and (user.id = groupu.user_id and user.id = t.auth) and (user.dept_id = dept.id and user.id = t.auth)) WHERE ct.is_deleted = 2 and au.is_deleted=2 and t.is_deleted=2 and t.status = 1
and ct.sw_id = #{swId}
and user.id=#{uid} and au.kb_auth =3 ORDER BY RAND() limit #{map.rows}

select distinct * from (select t.id, title, ct.sw_id as swId, user.real_name as userName, t.create_time as createTime, ct.name as categoryName, t. is_deleted from kb_basic t join castle_sys_user user on user.id = t.auth join kb_category ct on ct.id = t.category_id join kb_warehouse_auth au on ((t.id = au.wh_id and au.category = 01 and au.status = 1) or (t.id = au.wh_id and au.category = 01 and au.status = 2) or (t.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id, user.id uid,dept.parents from castle_sys_dept dept join castle_sys_user user on user.dept_id = dept.id) dept on ( dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) where ct.is_deleted = 2 and t.status=1 and (au.user_id =#{uid} or groupu.user_id=#{uid} or dept.uid=#{uid}) and au.kb_auth in (
#{kb_auth}
) union select t.id, title, ct.sw_id as swId, user.real_name as userName, t.create_time as createTime, ct.name as categoryName, t.is_deleted from kb_basic t join kb_category ct on ct.id = t.category_id join kb_warehouse_auth au on ((ct.id = au.wh_id and au.category = 01 and au.status = 1) or (ct.id = au.wh_id and au.category = 01 and au.status = 2) or (ct.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join castle_sys_dept dept on (dept.id = au.user_id or dept.parents like concat('%',au.user_id,'%')) join castle_sys_user user on (user.id = t.auth and au.user_id = user.id or (user.id = groupu.user_id and user.id = t.auth) or (user.dept_id = dept.id and user.id = t.auth)) where ct.is_deleted = 2 and t.status=1 and user.id=#{uid} and au.kb_auth =3) t2 where t2.is_deleted=2
ORDER BY t2.createTime desc limit 16

select distinct t2.* from (select t.id, title, ct.sw_id as swId, user.real_name as userName, t.create_time as createTime, ct.name as categoryName from kb_basic t join kb_category ct on ct.id = t.category_id join kb_warehouse_auth auth on auth.wh_id = ct.id join (select max(create_time) create_time, user_id, b_id from kb_basic_user where type=1 group by user_id,b_id) base_user on base_user.b_id = t.id join castle_sys_user user on user.id =t.auth where ct.is_deleted = 2 and t.is_deleted=2 and t.status=1 and base_user.user_id = #{uid} and t.status = 1
and ct.sw_id = #{swId}
ORDER BY base_user.create_time desc) t2 order by t2.createTime desc limit #{size}

select distinct t2.* from (select t.id, title, ct.sw_id as swId, user.real_name as userName, base_user.create_time as createTime, ct.name as categoryName
from kb_basic t join castle_sys_user user on user.id = t.auth join kb_category ct on ct.id = t.category_id join kb_warehouse_auth auth on auth.wh_id = ct.id join (select max(create_time) create_time, user_id, b_id from kb_basic_user where type=1 group by user_id,b_id) base_user on base_user.b_id = t.id where ct.is_deleted = 2 and t.is_deleted=2 and t.status=1 and base_user.user_id = #{uid} and t.status = 1
and ct.sw_id = #{swId}
ORDER BY base_user.create_time desc) t2 order by t2.createTime desc limit #{size}

select distinct t2.* from (select t.id, title, t.status as status, ct.sw_id as swId, user.real_name as createUser, kbu.create_time as pubTime, ct.name as ctName, ku.readCount from (select max(create_time) create_time, b_id,status,user_id from kb_basic_user where type= #{kbBaseShowDto.status} group by b_id,status,user_id) kbu left join kb_basic t on kbu.b_id = t.id left join castle_sys_user user on user.id = t.auth left join kb_category ct on ct.id = t.category_id left join kb_warehouse_auth au on ((t.id = au.wh_id and au.category = 01 and au.status = 1) or (t.id = au.wh_id and au.category = 01 and au.status = 2) or (t.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select count(1) as readCount,b_id from kb_basic_user where type= 1 group by b_id) ku on t.id = ku.b_id left join (select dept.id, user.id uid from castle_sys_dept dept join castle_sys_user user on user.dept_id = dept.id) dept on dept.id = au.user_id where ct.is_deleted = 2 and (au.user_id =#{userId} or groupu.user_id=#{userId} or dept.uid=#{userId}) and t.auth != #{userId} and kbu.user_id = #{userId} and kbu.status = #{kbBaseShowDto.type} and t.status = 1 and t.is_deleted = 2 and au.kb_auth in (
#{kb_auth}
)
and t.category_id in (
#{kcId}
)
and ct.sw_id in (
#{swId}
)
and t.title like concat('%',#{kbBaseShowDto.title},'%')
and kbu.create_time like concat(#{kbBaseShowDto.fromTime},'%')
union select t.id, title, t.status as status, ct.sw_id as swId, user.real_name as createUser, kbu.create_time as pubTime, ct.name as ctName, ku.readCount from (select max(create_time) create_time, b_id,status,user_id from kb_basic_user where type= #{kbBaseShowDto.status} group by b_id,status,user_id) kbu left join kb_basic t on kbu.b_id = t.id left join castle_sys_user user on user.id = t.auth left join kb_category ct on ct.id = t.category_id left join kb_warehouse_auth au on ((t.id = au.wh_id and au.category = 01 and au.status = 1) or (t.id = au.wh_id and au.category = 01 and au.status = 2) or (t.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select count(1) as readCount,b_id from kb_basic_user where type= 1 group by b_id) ku on t.id = ku.b_id left join (select dept.id, user.id uid from castle_sys_dept dept join castle_sys_user user on user.dept_id = dept.id) dept on dept.id = au.user_id where ct.is_deleted = 2 and kbu.user_id = #{userId} and (au.user_id =#{userId} or groupu.user_id=#{userId} or dept.uid=#{userId}) and t.auth = #{userId} and kbu.status = #{kbBaseShowDto.type} and t.is_deleted = 2 and au.kb_auth in (
#{kb_auth}
)
and t.category_id in (
#{kcId}
)
and ct.sw_id in (
#{swId}
)
and t.title like concat('%',#{kbBaseShowDto.title},'%')
and kbu.create_time like concat(#{kbBaseShowDto.fromTime},'%')
