select distinct t.category_id from kb_basic t join castle_sys_user user on user.id = t.auth join kb_category ct on ct.id = t.category_id join kb_warehouse_auth au on ((t.id = au.wh_id and au.category = 01 and au.status = 1) or (t.id = au.wh_id and au.category = 01 and au.status = 2) or (t.id = au.wh_id and au.category = 01 and au.status = 3) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 1) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 2) or (ct.sw_id = au.wh_id and au.category = 02 and au.status = 3)) left join kb_groups_user groupu on groupu.group_id = au.user_id left join (select dept.id, user.id uid from castle_sys_dept dept join castle_sys_user user on user.dept_id = dept.id) dept on dept.id = au.user_id where ct.is_deleted = 2 and t.status = 1 and (au.user_id =#{userId} or groupu.user_id = #{userId} or dept.uid = #{userId}) and au.kb_auth in (
#{kb_auth}
)

select t4.name, t4.num from (select t1.name, t1.sort, sum(ifnull(t3.count, 0)) num from (select * from kb_subject_warehouse where is_deleted = 2 and status = 1) t1 left join (select * from kb_category where is_deleted = 2) t2 on t1.id = t2.sw_id join (select category_id, count(1) count from kb_basic where is_deleted = 2 and status = 1 and category_id in(
#{item}
) and auth=#{userId} group by 1) t3 on t3.category_id = t2.id group by 1, 2 order by num desc limit #{num}) t4 order by t4.sort desc
